// Parse PostHog HogQL response and build funnel rows for /api/internal/growth/funnel.
// Expected response shape: { results: [[visit, signup, onboard, first_action, paid]], columns: [...] }
const response = $input.first().json;
const raw = Array.isArray(response?.results) ? response.results[0] ?? [] : [];
const [visit, signup, onboard, firstAction, paid] = [0, 1, 2, 3, 4].map(
  (i) => Number(raw[i]) || 0,
);

// snapshotDate = вчора у Kyiv-tz (стабільно навколо опівночі).
const fmt = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Kyiv',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
});
const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);
const snapshotDate = fmt.format(yesterday);

function conv(numerator, denominator) {
  if (!denominator || denominator <= 0) return null;
  return Math.round((numerator / denominator) * 10000) / 10000;
}

const rows = [
  { step: 'visit', stepOrder: 1, segment: 'all', count: visit, conversionRate: null },
  { step: 'signup', stepOrder: 2, segment: 'all', count: signup, conversionRate: conv(signup, visit) },
  { step: 'onboard', stepOrder: 3, segment: 'all', count: onboard, conversionRate: conv(onboard, signup) },
  { step: 'first_action', stepOrder: 4, segment: 'all', count: firstAction, conversionRate: conv(firstAction, onboard) },
  { step: 'paid', stepOrder: 5, segment: 'all', count: paid, conversionRate: conv(paid, firstAction) },
];

return [
  {
    json: {
      snapshotDate,
      rows,
      summary: { visit, signup, onboard, firstAction, paid },
    },
  },
];
